def gen(rng, size):
    n = max(1, size)
    haystack = ''.join(rng.choice('ab') for _ in range(n))
    m = rng.randint(1, min(6, n))
    if rng.random() < 0.6:
        start = rng.randrange(0, n - m + 1)
        needle = haystack[start:start + m]
    else:
        needle = ''.join(rng.choice('ab') for _ in range(m))
    return [haystack, needle]

