var strStr = function(haystack, needle) {
    const n = haystack.length, m = needle.length;
    if (m === 0) return 0;
    for (let i = 0; i + m <= n; i++) {
        let j = 0;
        while (j < m && haystack[i + j] === needle[j]) j++;
        if (j === m) return i;
    }
    return -1;
};
